package com.busantrip.service;
import com.busantrip.controller.AiChatController.*;import com.fasterxml.jackson.databind.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import org.springframework.web.reactive.function.client.WebClient;import reactor.core.publisher.Mono;import java.util.*;
@Service public class GeminiChatService{private final WebClient client;private final ObjectMapper mapper;private final String key,model;public GeminiChatService(WebClient.Builder b,ObjectMapper mapper,@Value("${external-api.gemini.base-url:https://generativelanguage.googleapis.com}")String base,@Value("${external-api.gemini.api-key:}")String key,@Value("${external-api.gemini.model:gemini-2.5-flash}")String model){this.client=b.baseUrl(base.trim()).build();this.mapper=mapper;this.key=key.trim();this.model=model.trim();}public Mono<Response> chat(Request r){if(r==null||r.message()==null||r.message().isBlank())return Mono.error(new IllegalArgumentException("메시지를 입력해주세요."));if(key.isBlank())return Mono.just(new Response("Gemini API 키가 설정되지 않았습니다.",List.of("현재 위치 주변 추천","덜 걷는 일정","실내 코스")));String prompt="당신은 부산 여행 서비스 ROAMATE의 실시간 AI 여행 비서입니다. 현재 위치, 선택 장소, 경로와 검색 결과를 고려해 5문장 이내의 실행 가능한 한국어 답변을 하세요. 확인되지 않은 운영시간이나 혼잡도를 단정하지 마세요.\n문맥:"+String.valueOf(r.context())+"\n최근 대화:"+String.valueOf(r.history())+"\n사용자:"+r.message();Map<String,Object> body=Map.of("contents",List.of(Map.of("role","user","parts",List.of(Map.of("text",prompt)))),"generationConfig",Map.of("temperature",.55,"maxOutputTokens",900));return client.post().uri(u->u.path("/v1beta/models/{model}:generateContent").queryParam("key",key).build(model)).bodyValue(body).retrieve().bodyToMono(String.class).map(this::parse).onErrorReturn(new Response("AI 응답을 불러오지 못했습니다. 잠시 후 다시 시도해주세요.",List.of("경로 다시 계산","숨은 명소 추천","비 피하기")));}private Response parse(String json){try{JsonNode root=mapper.readTree(json);String text=root.path("candidates").path(0).path("content").path("parts").path(0).path("text").asText("여행 요청을 이해했습니다.");return new Response(text,List.of("비 안 맞는 코스로 바꿔줘","덜 걷는 일정으로 바꿔줘","숨은 명소를 추가해줘","지금 주변 맛집 추천해줘"));}catch(Exception e){return new Response("AI 응답을 해석하지 못했습니다.",List.of("경로 다시 계산","실내 코스 추천"));}}
}
